/* Understated developer documentation block */
.doc-download-card {
  display: grid !important;
  gap: 8px !important;
  padding: 16px 18px !important;
  border-radius: 18px !important;
  border: 1px solid rgba(148, 163, 184, 0.20) !important;
  background: rgba(15, 33, 56, 0.72) !important;
  box-shadow: none !important;
  color: #d7e2ee !important;
}

.doc-download-card strong {
  color: #f4f8fc !important;
  font-size: 15px !important;
  letter-spacing: 0.01em !important;
}

.doc-download-card .footnote {
  max-width: 440px !important;
  color: #aebdca !important;
  font-size: 13px !important;
  line-height: 1.55 !important;
}

.doc-download-link {
  width: fit-content !important;
  min-height: 34px !important;
  padding: 0 13px !important;
  border-radius: 10px !important;
  border: 1px solid rgba(99, 156, 216, 0.34) !important;
  background: rgba(11, 92, 171, 0.20) !important;
  color: #cfe7ff !important;
  font-size: 12.5px !important;
  font-weight: 760 !important;
  box-shadow: none !important;
  text-decoration: none !important;
  transition: background 0.16s ease, border-color 0.16s ease, color 0.16s ease, transform 0.16s ease !important;
}

.doc-download-link:hover {
  background: rgba(11, 92, 171, 0.32) !important;
  border-color: rgba(99, 156, 216, 0.56) !important;
  color: #ffffff !important;
  transform: translateY(-1px) !important;
  box-shadow: none !important;
}

.doc-download-link:active {
  transform: translateY(0) !important;
}
